import os
import subprocess

def image_convert_handler(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    conversion_options = event.get('conversion_options', '')
    
    input_path = f'/tmp/{file_name}'
    output_path = f'/tmp/{os.path.splitext(file_name)[0]}_converted.jpg'
    
    convert_command = ['convert', input_path, *conversion_options.split(), output_path]
    
    subprocess.call(convert_command)
    
    return {
        'statusCode': 200,
        'body': f'Image {file_name} converted successfully.'
    }